package com.evolua.user.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "profiles") public class ProfileEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; private String displayName; private String bio; private Integer journeyLevel; private Boolean premium; private Instant createdAt; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getDisplayName() { return displayName; } public void setDisplayName(String displayName) { this.displayName = displayName; } public String getBio() { return bio; } public void setBio(String bio) { this.bio = bio; } public Integer getJourneyLevel() { return journeyLevel; } public void setJourneyLevel(Integer journeyLevel) { this.journeyLevel = journeyLevel; } public Boolean getPremium() { return premium; } public void setPremium(Boolean premium) { this.premium = premium; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
